  1→<?php
  2→
  3→namespace App\Services;
  4→
  5→use App\Models\OwnerMd;
  6→use App\Models\SfuserMd;
  7→use Exception;
  8→use Illuminate\Http\Client\Response;
  9→use Illuminate\Http\Request;
 10→use Illuminate\Support\Arr;
 11→use Illuminate\Support\Facades\App;
 12→use Illuminate\Support\Facades\Log;
 13→use Illuminate\Support\Facades\Session;
 14→
 15→/**
 16→ * TransferRequestService 用于转发请求到业务后端。
 17→ */
 18→class TransferRequestService
 19→{
 20→    use ServiceTrait;
 21→
 22→    /**
 23→     * 转发请求给后端服务器，同时对请求参数和响应结果做一些处理.
 24→     *
 25→     * @param Request $request 请求
 26→     * @param mixed $action
 27→     * @throws \App\Exceptions\UserException
 28→     * @throws \App\Exceptions\ServerException
 29→     * @throws \App\Exceptions\AuthorizationException
 30→     * @throws \App\Exceptions\CommonException
 31→     * @throws \App\Exceptions\CryptoException
 32→     * @throws \App\Exceptions\ResourceException
 33→     * @return array 请求参数处理后的新的参数
 34→     */
 35→    public function transfer(Request $request, string $action = ''): mixed
 36→    {
 37→        $params = $request->all();
 38→
 39→        // 提取特定的请求参数
 40→        $reservedWords = [
 41→            'decrypt_config', 'encrypt_config', 'update_permission', 'next_replace_filter',
 42→            'hash_filter', 'replace_filter', 'authorize_config', 'intact_columns', 'response_format',
 43→            'ai_analysis_config',
 44→        ];
 45→        foreach ($reservedWords as $word) {
 46→            ${$word} = $params[$word] ?? null;
 47→            unset($params[$word]);
 48→        }
 49→
 50→        // 对请求参数进行加密
 51→        if (!empty($encrypt_config)) {
 52→            if (Arr::isAssoc($encrypt_config)) {
 53→                $encrypt_config = [$encrypt_config];
 54→            }
 55→            foreach ($encrypt_config as $conf) {
 56→                $params = EncryptService::app()->encryptData($params, $conf);
 57→            }
 58→        } else {
 59→            // 分页、版本号、语言控制参数应当默认放行
 60→            $intact_columns = array_merge_index($intact_columns ?? [], ['version_info', 'sys_lang', 'page', 'per_page']);
 61→            // 对所有 intact_columns 之外的属性进行 unset，该字段无需递归处理
 62→            $intact_columns = Arr::wrap($intact_columns);
 63→            $params = Arr::only($params, $intact_columns);
 64→        }
 65→
 66→        // 处理请求参数中“更新权限”的操作
 67→        if (!empty($update_permission)) {
 68→            if (Arr::isAssoc($update_permission)) {
 69→                $update_permission = [$update_permission];
 70→            }
 71→            foreach ($update_permission as $conf) {
 72→                $params = ResourceService::app()->updateResPermission($params, $conf);
 73→            }
 74→        }
 75→
 76→        // 处理请求参数中“哈希筛选”的参数
 77→        if (!empty($hash_filter)) {
 78→            $params = HashFilterService::app()->hashFilter($params, $hash_filter);
 79→        }
 80→
 81→        // 处理请求参数中“替换筛选”的参数
 82→        if (!empty($replace_filter)) {
 83→            $params = ReplaceFilterService::app()->replaceFilter($params, $replace_filter);
 84→        }
 85→
 86→        if (!empty($next_replace_filter)) {
 87→            $params = NextReplaceFilterService::app()->replaceFilter($params, $next_replace_filter);
 88→        }
 89→
 90→        // 处理请求参数中“授权”参数
 91→        if (!empty($authorize_config)) {
 92→            $token = AuthorizeService::app()->generateToken($authorize_config);
 93→            $params['authorized_token'] = $token;
 94→        }
 95→
 96→        // 有些接口是 stream response，这部分请求没办法用通用的 JSON 方式处理，所以这里直接转发，为了避免造成破坏性变更
 97→        // 这里只对部分接口进行特殊处理
 98→        if (!empty($response_format) && $response_format == 'stream') {
 99→            // 如果同时有 ai_analysis_config，需要先拿完整响应再做 AI streaming
100→            if (!empty($ai_analysis_config) && !empty($ai_analysis_config['system_prompt'])) {
101→                Log::info('[lbl][0416-AI日报][TransferRequest] AI stream: 开始调用后端', [
102→                    'uri' => $action ?: $request->path(),
103→                    'ai_config_keys' => array_keys($ai_analysis_config),
104→                ]);
105→                $resp = $this->callBackendApi($action ?: $request->path(), $params);
106→                Log::info('[lbl][0416-AI日报][TransferRequest] AI stream: 后端响应', [
107→                    'has_data' => !empty($resp['data']),
108→                    'error_code' => $resp['error_code'] ?? 'N/A',
109→                    'error_msg' => $resp['error_msg'] ?? '',
110→                    'resp_keys' => is_array($resp) ? array_keys($resp) : 'not_array',
111→                ]);
112→                if (!empty($resp['data'])) {
113→                    $respData = &$resp['data'];
114→
115→                    // 解密
116→                    $decrypt_config = empty($respData['decrypt_config']) ? $decrypt_config : array_merge($decrypt_config ?? [], $respData['decrypt_config']);
117→                    if (isset($respData['decrypt_config'])) {
118→                        unset($respData['decrypt_config']);
119→                    }
120→                    if (!empty($decrypt_config)) {
121→                        // AI 场景容忍部分解密失败（throwEcp(false)），避免单个字段权限不足导致整体中断
122→                        $respData = DecryptService::app()->throwEcp(false)->decryptData($respData, $decrypt_config, $decrypt_config['operation'] ?? 'response');
123→                    }
124→
125→                    // 合并响应中的 ai_analysis_config（oa-server 可在响应中提供/覆盖 AI 配置）
126→                    if (!empty($respData['ai_analysis_config'])) {
127→                        $ai_analysis_config = array_merge($ai_analysis_config, $respData['ai_analysis_config']);
128→                        unset($respData['ai_analysis_config']);
129→                    }
130→
131→                    // 提取 AI 输入内容
132→                    $targetField = $ai_analysis_config['target_field'] ?? null;
133→                    $contentForAi = $targetField ? data_get($respData, $targetField, '') : json_encode($respData, JSON_UNESCAPED_UNICODE);
134→                    if (is_array($contentForAi)) {
135→                        $contentForAi = json_encode($contentForAi, JSON_UNESCAPED_UNICODE);
136→                    }
137→
138→                    // compress=true 时去掉 HTML 标签、压缩空白，减少 AI token 消耗
139→                    if (!empty($ai_analysis_config['compress'])) {
140→                        $contentForAi = strip_tags($contentForAi);
141→                        $contentForAi = preg_replace('/\n{3,}/', "\n\n", $contentForAi);
142→                        $contentForAi = preg_replace('/[ \t]+/', ' ', $contentForAi);
143→                        $contentForAi = trim($contentForAi);
144→                    }
145→
146→                    $systemPrompt = $ai_analysis_config['system_prompt'];
147→                    $history = $ai_analysis_config['history'] ?? [];
148→
149→                    // 移除 target_field 对应的大字段，剩余字段作为 meta 发给前端
150→                    if ($targetField) {
151→                        data_set($respData, $targetField, null);
152→                    }
153→                    $metaData = array_filter($respData, fn ($v) => $v !== null);
154→
155→                    Log::info('[lbl][0416-AI日报][TransferRequest] AI stream: 开始 SSE 流', [
156→                        'content_for_ai' => mb_substr($contentForAi, 0, 500),
157→                        'content_len' => mb_strlen($contentForAi),
158→                        'system_prompt' => mb_substr($systemPrompt, 0, 200),
159→                        'prompt_len' => mb_strlen($systemPrompt),
160→                        'history_count' => count($history),
161→                        'meta_keys' => array_keys($metaData),
162→                        'target_field' => $targetField,
163→                        'compress' => !empty($ai_analysis_config['compress']),
164→                        'resp_data_keys' => array_keys($respData),
165→                    ]);
166→                    return response()->stream(function () use ($contentForAi, $systemPrompt, $history, $metaData) {
167→                        // 首帧：发送 oa-server 返回的元数据（如 session_id、summary 等）
168→                        if (!empty($metaData)) {
169→                            echo 'data: '.json_encode([
170→                                'error_code' => 0,
171→                                'error_msg' => '',
172→                                'data' => array_merge(['type' => 'meta'], $metaData),
173→                            ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
174→                            ob_flush();
175→                            flush();
176→                        }
177→
178→                        AiAnalysisService::app()->analyzeStream(
179→                            $contentForAi,
180→                            $systemPrompt,
181→                            function (string $chunk) {
182→                                echo 'data: '.json_encode([
183→                                    'error_code' => 0,
184→                                    'error_msg' => '',
185→                                    'data' => ['type' => 'chat', 'is_finished' => false, 'content' => $chunk],
186→                                ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
187→                                ob_flush();
188→                                flush();
189→                            },
190→                            $history
191→                        );
192→                        // 结束帧
193→                        echo 'data: '.json_encode([
194→                            'error_code' => 0,
195→                            'error_msg' => '',
196→                            'data' => ['type' => 'chat', 'is_finished' => true, 'content' => ''],
197→                        ], JSON_UNESCAPED_UNICODE).PHP_EOL.PHP_EOL;
198→                        ob_flush();
199→                        flush();
200→                    }, 200, [
201→                        'Content-Type' => 'text/event-stream',
202→                        'Cache-Control' => 'no-cache',
203→                        'X-Accel-Buffering' => 'no',
204→                    ]);
205→                }
206→
207→                // 后端返回错误（data 为空），以 SSE 格式返回错误信息给前端
208→                $errorMsg = $resp['error_msg'] ?? '后端服务返回错误';
209→                $errorCode = $resp['error_code'] ?? -1;
210→                Log::warning('[lbl][0416-AI日报][TransferRequest] AI stream: 后端返回错误, 以 SSE 返回', [
211→                    'error_code' => $errorCode,
212→                    'error_msg' => $errorMsg,
213→                ]);
214→                return response()->json([
215→                    'error_code' => $errorCode,
216→                    'error_msg' => $errorMsg,
217→                    'data' => null,
218→                ]);
219→            }
220→
221→            // 原有的 stream 透传逻辑不变
222→            $resp = $this->callBackendApi($action ?: $request->path(), $params, true);
223→            return response()->stream(function () use ($resp) {
224→                $body = $resp->toPsrResponse()->getBody();
225→                $content = '';
226→                while (!$body->eof()) {
227→                    $bit = $body->read(1);
228→                    $content .= $bit;
229→                    if (substr($content, -2) == PHP_EOL.PHP_EOL) {
230→                        echo $content;
231→                        ob_flush();
232→                        flush();
233→                        $content = '';
234→                    }
235→                }
236→            }, $resp->status(), array_merge($resp->headers(), ['X-Accel-Buffering' => 'no']));
237→        }
238→
239→        $resp = $this->callBackendApi($action ?: $request->path(), $params);
240→        if (!empty($resp['data'])) {
241→            $respData = &$resp['data'];
242→            // 响应中有 decrypt_config 的话，与请求中的 decrypt_config 合并（相同键名以响应中的为准）
243→            $decrypt_config = empty($respData['decrypt_config']) ? $decrypt_config : array_merge($decrypt_config ?? [], $respData['decrypt_config']);
244→            if (isset($respData['decrypt_config'])) {
245→                unset($respData['decrypt_config']);
246→            }
247→            if (!empty($decrypt_config)) {
248→                $respData = DecryptService::app()->decryptData($respData, $decrypt_config, $decrypt_config['operation'] ?? 'response');
249→            }
250→
251→            // 合并响应中的 ai_analysis_config（oa-server 可在响应中提供/覆盖 AI 配置）
252→            if (!empty($respData['ai_analysis_config'])) {
253→                $ai_analysis_config = array_merge($ai_analysis_config ?? [], $respData['ai_analysis_config']);
254→                unset($respData['ai_analysis_config']);
255→            }
256→
257→            // AI 分析（解密之后执行，仅当 ai_analysis_config 存在时）
258→            if (!empty($ai_analysis_config) && !empty($ai_analysis_config['system_prompt'])) {
259→                $targetField = $ai_analysis_config['target_field'] ?? null;
260→                $outputField = $ai_analysis_config['output_field'] ?? 'ai_analysis';
261→                $contentForAi = $targetField ? data_get($respData, $targetField, '') : json_encode($respData, JSON_UNESCAPED_UNICODE);
262→
263→                if (is_array($contentForAi)) {
264→                    $contentForAi = json_encode($contentForAi, JSON_UNESCAPED_UNICODE);
265→                }
266→
267→                Log::info('[lbl][0416-AI日报][TransferRequest] blocking AI 调用', [
268→                    'target_field' => $targetField,
269→                    'output_field' => $outputField,
270→                    'content_for_ai' => mb_substr(is_string($contentForAi) ? $contentForAi : json_encode($contentForAi), 0, 500),
271→                    'content_len' => mb_strlen(is_string($contentForAi) ? $contentForAi : ''),
272→                    'prompt_len' => mb_strlen($ai_analysis_config['system_prompt']),
273→                    'prompt_preview' => mb_substr($ai_analysis_config['system_prompt'], 0, 200),
274→                    'resp_data_keys' => array_keys($respData),
275→                ]);
276→
277→                $aiResult = AiAnalysisService::app()->analyze(
278→                    $contentForAi,
279→                    $ai_analysis_config['system_prompt']
280→                );
281→
282→                Log::info('[lbl][0416-AI日报][TransferRequest] blocking AI 结果', [
283→                    'result_len' => mb_strlen($aiResult),
284→                    'result_preview' => mb_substr($aiResult, 0, 500),
285→                ]);
286→
287→                data_set($respData, $outputField, $aiResult);
288→            }
289→        }
290→
291→        return $resp;
292→    }
293→
294→    public function transferWithoutEncryptionProcess(Request $request, string $action = '', bool $retOrigResp = false): mixed
295→    {
296→        // 该请求不会做任何涉及到加解密的操作，直接转发即可，基于对三方的不信任，我们也不提供 hash/replace 之类的筛选
297→        $params = $request->all();
298→        $user = auth()->user()->getAuthIdentifier();
299→        $sfuser = SfuserMd::find($user);
300→        $params['sfuser_info'] = [
301→            'id' => $sfuser->id,
302→            'is_admin' => $sfuser->is_admin,
303→            'auth_source' => SfuserMd::AUTH_SOURCE_TOKEN,
304→            // 权限也一并不传递，尽力约束三方应用可以执行的操作
305→            'permissions' => [],
306→            'res_attrs' => [],
307→        ];
308→
309→        $fallbackSite = $sfuser->site;
310→        $site = $request->input('sys_site', $fallbackSite);
311→        // 如果 site 非法，使用我们默认的 site
312→        if (!in_array(strtoupper($site), config('my_sites.active_backend_sites'))) {
313→            $site = $fallbackSite;
314→        }
315→        SiteService::app()->setSite($site);
316→        $params['sys_lang'] = App::currentLocale();
317→        // 转发客户端 IP，以便后端某些接口针对 ip 进行过滤或者限流
318→        $params['client_ip'] = \Illuminate\Support\Facades\Request::ip();
319→
320→        $uri = $action ?: $request->path();
321→        if ($retOrigResp) {
322→            return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params, ['stream' => true], true);
323→        }
324→
325→        return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params);
326→    }
327→
328→    /**
329→     * 调用后端接口。
330→     *
331→     * @param string $uri 请求地址
332→     * @param array $params 请求参数
333→     * @return array|Response 后端返回值
334→     */
335→    protected function callBackendApi(string $uri, array $params, bool $retOrigResp = false): array|Response
336→    {
337→        $params['sfuser_info'] = Arr::only(Session::get('sfuser', []), ['id', 'is_admin', 'auth_source']);
338→        $owner = null;
339→        try {
340→            $owner = OwnerMd::find();
341→        } catch (Exception $e) {
342→            Log::error('get perm error', [
343→                'e' => $e,
344→            ]);
345→        }
346→
347→        // 为了减少转发的请求的 payload 的大小，员工端不转发 permissions/res_attrs，针对员工端请求，后端暂时不需要通过权限过滤数据
348→        $authType = App::get('sys_auth_type');
349→        $params['sfuser_info']['permissions'] = (isset($owner) && $authType != 'staff') ? $owner->getPermissions() : [];
350→        $params['sfuser_info']['res_attrs'] = (isset($owner) && $authType != 'staff') ? $owner->getResAttrs() : [];
351→
352→        // 将支持的语言也一并转发到后端，以便支持本地化选项
353→        $params['sys_lang'] = App::currentLocale();
354→        // 转发客户端 IP，以便后端某些接口针对 ip 进行过滤或者限流
355→        $params['client_ip'] = \Illuminate\Support\Facades\Request::ip();
356→
357→        if ($retOrigResp) {
358→            return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params, ['stream' => true, 'timeout' => 1200], true);
359→        }
360→
361→        return ApiService::appWith('backend')->allowError()->sendRequest($uri, $params);
362→    }
363→}
